const staticData = $getWorkflowStaticData('global');
staticData.sisterPosted = staticData.sisterPosted || {};
const sisterPosted = staticData.sisterPosted;
const feeds = [
  'https://waxandwane.store/blogs/wax-wane-blog.atom',
  'https://waxandwane.store/blogs/why-korean-skincare.atom',
  'https://waxandwane.store/blogs/electromagnetic-frequency-radiation.atom',
  'https://waxandwane.store/blogs/crystals-science-magic.atom',
];
const PRODUCT_KEYWORDS = {
  haramoon: { name: 'HARAMOON K-Beauty Collection', keyword: 'haramoon', shop_url: 'https://waxandwane.store/collections/haramoon-korean-skincare', hashtags: '#HARAMOON #KBeauty #KoreanSkincare #GlowingSkin #SkinBarrier #GlassSkin #SkincareRoutine #KBeautyCommunity #WaxAndWane', emoji: '✨💙' },
  faraday: { name: 'Faraday Bag EMF Protection', keyword: 'faraday', shop_url: 'https://waxandwane.store/collections/emf-shielding-faraday-protection', hashtags: '#FaradayBag #EMFProtection #TechHealth #DigitalWellness #5GProtection #EMFShielding #WaxAndWane', emoji: '🛡️⚡' },
  emf: { name: 'EMF Protection Collection', keyword: 'emf', shop_url: 'https://waxandwane.store/collections/emf-shielding-faraday-protection', hashtags: '#EMFProtection #FaradayBag #TechHealth #DigitalWellness #5GProtection #WaxAndWane', emoji: '🛡️⚡' },
  moonstone: { name: 'Moonstone Crystal Collection', keyword: 'moonstone', shop_url: 'https://waxandwane.store/collections/natural-crystals-gemstones', hashtags: '#Moonstone #Crystals #CrystalHealing #Wellness #Spirituality #CrystalEnergy #WaxAndWane', emoji: '🌙💎' },
  crystal: { name: 'Crystal & Wellness Collection', keyword: 'crystal', shop_url: 'https://waxandwane.store/collections/natural-crystals-gemstones', hashtags: '#Crystals #CrystalHealing #Wellness #Spirituality #CrystalEnergy #Mindfulness #WaxAndWane', emoji: '💎✨' },
  skincare: { name: 'HARAMOON K-Beauty Skincare', keyword: 'skincare', shop_url: 'https://waxandwane.store/collections/haramoon-korean-skincare', hashtags: '#Skincare #KBeauty #HARAMOON #GlowingSkin #SkincareRoutine #SkinBarrier #WaxAndWane', emoji: '✨💙' },
  serum: { name: 'HARAMOON Skincare Serums', keyword: 'serum', shop_url: 'https://waxandwane.store/collections/haramoon-korean-skincare', hashtags: '#Serum #KBeauty #HARAMOON #GlowingSkin #SkincareRoutine #AntiAging #WaxAndWane', emoji: '✨💙' },
};

function parseAtomLinks(xml) {
  return xml.split('<entry>').slice(1)
    .map(b => (b.match(/<link[^>]+href="([^"]+)"/) || [])[1])
    .filter(Boolean);
}

const allPosts = [];
for (const feedUrl of feeds) {
  try {
    const xml = await this.helpers.httpRequest({ method: 'GET', url: feedUrl });
    for (const link of parseAtomLinks(String(xml))) {
      if (!allPosts.includes(link)) allPosts.push(link);
    }
  } catch (e) { /* skip feed */ }
}
if (!allPosts.length) return [{ json: { skip: true, message: 'No RSS posts found' } }];

let targetUrl = null;
for (const url of allPosts) {
  if (!sisterPosted[url]) { targetUrl = url; break; }
}
if (!targetUrl) {
  staticData.sisterPosted = {};
  targetUrl = allPosts[0];
}

const html = await this.helpers.httpRequest({ method: 'GET', url: targetUrl });
const bodyText = String(html).replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<style[\s\S]*?<\/style>/gi, '').replace(/<[^>]+>/g, ' ').toLowerCase();
const titleMatch = String(html).match(/<h1[^>]*>([\s\S]*?)<\/h1>/i);
const title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g, '').trim() : targetUrl;
const og = String(html).match(/<meta\s+property=["']og:image["']\s+content=["']([^"']+)["']/i);
const image_url = og ? og[1] : null;

let product = null;
for (const [kw, info] of Object.entries(PRODUCT_KEYWORDS)) {
  if (bodyText.includes(kw)) { product = info; break; }
}
if (!product) product = PRODUCT_KEYWORDS.skincare;

const fbCaption = `${product.emoji} Inspired by our latest blog post!\n\nWe just published "${title}" and wanted to spotlight the products that make it all possible.\n\n✨ Featured: ${product.name}\n\n📖 Read the full article: ${targetUrl}\n\n🛍️ Shop now: ${product.shop_url}\n\n#WaxAndWane #ShopSmall #SmallBusiness ${product.hashtags}`;
const igCaption = `${product.emoji} We just dropped a new blog post and had to spotlight this!\n\n${product.name} - because your routine deserves the best.\n\n👆 Link in bio to shop + read the full article!\n\n${product.hashtags} #ShopSmall #SmallBusiness #WaxAndWane`;

return [{ json: { skip: false, url: targetUrl, title, image_url, product, fbCaption, igCaption } }];

const art = $('Build Sister Captions').first().json;
if (art.skip) return [{ json: art }];
const staticData = $getWorkflowStaticData('global');
staticData.sisterPosted = staticData.sisterPosted || {};
staticData.sisterPosted[art.url] = { at: new Date().toISOString() };
return [{ json: { status: 'sister_posted', url: art.url, product: art.product?.name, finishedAt: new Date().toISOString() } }];
